#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline T Abs(const T&x){return x<0?-x:x;}
const int N=2510;int n,m,s;LL ans;int deg[N],loc[N];
int fa[N];inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
struct node{int u,v,w;inline bool operator <(const node &x)const{return w<x.w;}}E[N*N/2];int p;
inline bool lnk(const int &x,const int &y){int X=fnd(x),Y=fnd(y);if(X==Y)return false;return fa[X]=Y,true;}
inline LL work(const int &t)
{
	++deg[s];++deg[t];rep(1,n,i)fa[i]=i;lnk(loc[s],loc[t]);LL res=0;int lst=0;
	rep(1,n,i)if(deg[i]&1){if(lst){res+=i-lst;for(int j=lst;j<i;++j)lnk(loc[j],loc[i]);lst=0;}else lst=i;}
	p=0;rep(1,n,i)if(deg[i]){if(lst&&fnd(loc[i])!=fnd(loc[lst]))E[++p]=(node){loc[i],loc[lst],Abs(i-lst)};lst=i;}
	std::sort(E+1,E+p+1);rep(1,p,i)if(lnk(E[i].u,E[i].v))res+=E[i].w<<1;--deg[s];--deg[t];return res;
}
int main()
{
	n=read();m=read();s=read();rep(1,n,i)fa[i]=i;
	rep(1,m,i){int u=read(),v=read();++deg[u];++deg[v];ans+=Abs(u-v);lnk(u,v);}
	rep(1,n,i)loc[i]=fnd(i);rep(1,n,i)printf("%lld ",ans+work(i));
}
